#include "controller.h"

static void controller_set_outputs(controller_t *controller, bool filter_on, bool drain_open, controller_state_t state)
{
    controller->filter_on = filter_on;
    controller->drain_open = drain_open;
    controller->state = state;
}

static void controller_set_safe_idle(controller_t *controller)
{
    controller_set_outputs(controller, false, false, CONTROLLER_STATE_SAFE_IDLE);
}

static void controller_set_complete(controller_t *controller)
{
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
    controller_set_outputs(controller, false, false, CONTROLLER_STATE_COMPLETE);
}

static void controller_set_filtering(controller_t *controller)
{
    controller->settling_started_ms = 0U;
    controller_set_outputs(controller, true, false, CONTROLLER_STATE_FILTERING);
}

static void controller_set_settling(controller_t *controller, uint32_t now_ms)
{
    controller->settling_started_ms = now_ms;
    controller_set_outputs(controller, false, false, CONTROLLER_STATE_SETTLING);
}

static void controller_set_draining(controller_t *controller)
{
    controller->settling_started_ms = 0U;
    controller_set_outputs(controller, false, true, CONTROLLER_STATE_DRAINING);
}

static bool controller_has_seen_both_sensors(const controller_t *controller)
{
    return (controller->has_valid_turbidity && controller->has_valid_level);
}

static bool controller_sensors_are_fresh(const controller_t *controller, uint32_t now_ms)
{
    uint32_t turbidity_age;
    uint32_t level_age;

    if (!controller_has_seen_both_sensors(controller)) {
        return false;
    }

    turbidity_age = now_ms - controller->last_turbidity_ms;
    level_age = now_ms - controller->last_level_ms;
    return (turbidity_age <= CONTROLLER_SENSOR_TIMEOUT_MS) && (level_age <= CONTROLLER_SENSOR_TIMEOUT_MS);
}

static void controller_reset_process_timers(controller_t *controller)
{
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

static void controller_update_clear_streak(controller_t *controller, int turbidity_ntu)
{
    if (turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
        controller->clear_streak_count++;
    } else {
        controller->clear_streak_count = 0;
    }
}

static void controller_evaluate_state_machine(controller_t *controller, uint32_t now_ms)
{
    if (!controller_sensors_are_fresh(controller, now_ms)) {
        controller_set_safe_idle(controller);
        return;
    }

    if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
        controller_set_complete(controller);
        return;
    }

    if ((controller->state == CONTROLLER_STATE_COMPLETE) && (controller->last_level >= CONTROLLER_COMPLETE_LEVEL)) {
        controller_set_safe_idle(controller);
    }

    switch (controller->state) {
    case CONTROLLER_STATE_SAFE_IDLE:
        if ((controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) &&
            (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU)) {
            controller_set_filtering(controller);
        }
        break;
    case CONTROLLER_STATE_FILTERING:
        if ((controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) &&
            (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) &&
            (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU)) {
            controller_set_settling(controller, now_ms);
        }
        break;
    case CONTROLLER_STATE_SETTLING:
        if (controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
            controller_reset_process_timers(controller);
            controller_set_filtering(controller);
            break;
        }

        if (((now_ms - controller->settling_started_ms) >= CONTROLLER_SETTLING_MS) &&
            (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) &&
            (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL)) {
            controller_set_draining(controller);
        }
        break;
    case CONTROLLER_STATE_DRAINING:
        if ((controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU) &&
            (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL)) {
            controller_reset_process_timers(controller);
            controller_set_filtering(controller);
        }
        break;
    case CONTROLLER_STATE_COMPLETE:
        if ((controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) &&
            (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU)) {
            controller_set_filtering(controller);
        }
        break;
    default:
        controller_set_safe_idle(controller);
        break;
    }
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;
    bool fault_input = false;
    bool timed_out = false;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;
        controller_update_clear_streak(controller, input.turbidity_ntu);
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        fault_input = true;
        timed_out = true;
        break;
    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        fault_input = true;
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        break;
    }

    if (fault_input) {
        controller_reset_process_timers(controller);
        controller_set_safe_idle(controller);
    } else {
        controller_evaluate_state_machine(controller, input.now_ms);

        if ((controller->state == CONTROLLER_STATE_SAFE_IDLE) &&
            controller_has_seen_both_sensors(controller) &&
            controller_sensors_are_fresh(controller, input.now_ms) &&
            (controller->last_level < CONTROLLER_COMPLETE_LEVEL)) {
            controller_set_complete(controller);
        }
    }

    if ((controller->state == CONTROLLER_STATE_SAFE_IDLE) && controller_has_seen_both_sensors(controller) &&
        !controller_sensors_are_fresh(controller, input.now_ms)) {
        timed_out = true;
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);
    output.timed_out = timed_out;
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

