static bool controller_sensors_are_fresh(const controller_t *controller, uint32_t now_ms)
{
    uint32_t turbidity_age;
    uint32_t level_age;

    if (!controller_has_seen_both_sensors(controller)) {
        return false;
    }

    turbidity_age = now_ms - controller->last_turbidity_ms;
    level_age = now_ms - controller->last_level_ms;
    return (turbidity_age <= CONTROLLER_SENSOR_TIMEOUT_MS) && (level_age <= CONTROLLER_SENSOR_TIMEOUT_MS);
}

